import Image from "next/image";

// shadcn
import { Button } from "@/components/ui/button";

// constants
const products = [
  {
    name: "Apple Watch 4",
    price: "$280",
    image: "https://cdn.uiable.com/block/e-commerce10-1.jpg",
  },
  {
    name: "Nike React",
    price: "$140",
    image: "https://cdn.uiable.com/block/e-commerce10-2.jpg",
  },
  {
    name: "Steampunk Sunglass",
    price: "$170",
    image: "https://cdn.uiable.com/block/e-commerce10-3.jpg",
  },
  {
    name: "Dualshock 4",
    price: "$140",
    image: "https://cdn.uiable.com/block/e-commerce10-4.jpg",
  },
];

//  ------------------------------ | E - COMMERCE 10 | ------------------------------  //

export default function Ecommerce10() {
  return (
    <section className="bg-primary py-20 md:py-28">
      <div className="container mx-auto px-4">
        {/* Heading */}
        <div className="mx-auto mb-14 max-w-lg text-center text-primary-foreground">
          <p className="mb-4 text-lg font-medium uppercase tracking-widest text-yellow-500">
            E-Commerce
          </p>

          <h2 className="mb-6 text-white">Product You Need</h2>

          <p className="text-sm text-primary-foreground/80 md:text-base">
            This is a big one and I consider it one of the most important things
            for a designer to get right.
          </p>
        </div>

        {/* Grid */}
        <div className="grid grid-cols-12 gap-6">
          {/* Small Cards */}
          <div className="col-span-12 lg:col-span-6">
            <div className="grid grid-cols-12 gap-6">
              {products.map((item, index) => (
                <div
                  key={index}
                  className="col-span-12 sm:col-span-6 rounded-2xl bg-card shadow-sm overflow-hidden"
                >
                  {/* Image with text INSIDE */}
                  <div className="relative h-60 w-full">
                    <Image
                      src={item.image}
                      alt={item.name}
                      fill
                      className="object-contain p-6"
                    />

                    {/* Gradient overlay at bottom */}
                    <div className="absolute inset-x-0 bottom-0 h-28 bg-linear-to-t from-card via-card/80 to-transparent" />

                    {/* Text overlaid on image */}
                    <div className="absolute bottom-5 left-5 right-5">
                      <h5 className="mb-0.5">{item.name}</h5>
                      <p className="text-md text-muted-foreground">
                        {item.price}
                      </p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Featured Product */}
          <div className="col-span-12 lg:col-span-6">
            <div className="flex h-full flex-col rounded-2xl bg-card shadow-sm overflow-hidden">
              {/* Image with text INSIDE */}
              <div className="relative flex-1 min-h-40">
                <Image
                  src="https://cdn.uiable.com/block/e-commerce10-5.jpg"
                  alt="Macbook Pro"
                  fill
                  className="object-contain p-6"
                />

                {/* Gradient overlay at bottom */}
                <div className="absolute inset-x-0 bottom-0 h-28 bg-linear-to-t from-card via-card/80 to-transparent" />

                {/* Text + Button overlaid on image */}
                <div className="absolute bottom-6 left-6 right-6 grid grid-cols-12 items-end gap-6">
                  <div className="col-span-12 sm:col-span-7">
                    <h5 className="mb-1">Macbook Pro</h5>
                    <p className="text-md text-muted-foreground">$1800</p>
                  </div>

                  <div className="col-span-12 sm:col-span-5 sm:text-right">
                    <Button
                      className="bg-yellow-500 text-white hover:bg-yellow-400"
                      size="lg"
                    >
                      Shop Now
                    </Button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
